starterCode:
const siswa = {
  nama: 'Rina',
  nilai: { matematika: 90, bahasa: 85 },
  sapa: function() {
    return 'Halo, saya ' + this.nama;
  }
};

console.log(siswa.nilai.matematika);
console.log(siswa.sapa());
console.log(Object.keys(siswa).length);

verification.testCode:
// Jawaban B benar:
// - siswa.nilai.matematika mengakses 90 melalui dot notation berantai
// - siswa.sapa() memanggil method yang menggunakan this.nama
// - Object.keys(siswa) mengembalikan ['nama', 'nilai', 'sapa'] — 3 properti tingkat atas
const result = 'B';
assert(result === 'B', 'Jawaban salah. Object.keys hanya menghitung properti tingkat atas, bukan nested.');
